  const express = require('express');
  const cors = require('cors');
  const bodyParser = require('body-parser');
  const { MongoClient } = require('mongodb');

  const app = express();
  app.use(cors());
  app.use(bodyParser.json({ limit: '2mb' }));

  const mongoUrl = 'mongodb://localhost:27017';
  const dbName = 'collector';
  let db;

  MongoClient.connect(mongoUrl).then(client => {
    db = client.db(dbName);
    console.log('DB connected');
  });

  app.post('/ingest', async (req, res) => {
    const payload = req.body;
    await db.collection('events').insertOne(payload);
    res.json({ ok: true });
  });

  app.post('/geo', async (req, res) => {
    await db.collection('geo').insertOne(req.body);
    res.json({ ok: true });
  });

  app.get('/profiles/rebuild', async (req, res) => {
    // Aggregate events into profiles
    const events = await db.collection('events').find({}).toArray();
    const profiles = new Map();
    for (const e of events) {
      const sid = e.sessionId;
      if (!profiles.has(sid)) profiles.set(sid, { sessions: [], attrs: {} });
      const p = profiles.get(sid);
      p.sessions.push(e);
      if (e.events && e.events.length) {
        for (const evt of e.events) {
          if (evt.type === 'init') {
            Object.assign(p.attrs, evt.payload);
          }
        }
      }
    }
    const out = [];
    for (const [sid, p] of profiles.entries()) {
      out.push({ sessionId: sid, profile: p });
    }
    await db.collection('profiles').deleteMany({});
    if (out.length) await db.collection('profiles').insertMany(out);
    res.json({ ok: true, count: out.length });
  });

  app.listen(8080, () => console.log('Collector listening on 8080'));

